        SenderName = SenderName,
        WeightKg = WeightKg,
        Notes = Notes
    };
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        // GET all shipments (dispatchers)
        group.MapGet("/", async (ApplicationDbContext db, string? status, string? search) =>
        {
            var query = db.Shipments.AsQueryable();

            if (Enum.TryParse<ShipmentStatus>(status, true, out var parsedStatus))
            {
                query = query.Where(s => s.Status == parsedStatus);
            }

            if (!string.IsNullOrWhiteSpace(search))
            {
                var term = search.Trim();
                query = query.Where(s =>
                    s.TrackingNumber.Contains(term) ||
                    s.Destination.Contains(term) ||
                    s.RecipientName.Contains(term) ||
                    s.SenderName.Contains(term));
            }

            var shipments = await query
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => s.ToDto())
                .ToListAsync();

            return Results.Ok(shipments);
        }).RequireAuthorization("Dispatcher");

        // GET by tracking number (public for customers)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            return shipment is not null
                ? Results.Ok(shipment.ToDto())
                : Results.NotFound(new { Message = "Shipment not found." });
        }).RequireAuthorization();

        // PUT update status (dispatchers)
        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.Status;
            shipment.Notes = request.Notes ?? shipment.Notes;

            if (request.Status == ShipmentStatus.Delivered)
            {
                shipment.ActualDelivery = DateTime.UtcNow;
            }

            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        }).RequireAuthorization("Dispatcher");

        // POST create shipment (dispatchers)
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery,
                RecipientName = dto.RecipientName,
                SenderName = dto.SenderName,
                WeightKg = dto.WeightKg,
                Notes = dto.Notes
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", shipment.ToDto());
        }).RequireAuthorization("Dispatcher");
    }

    private static string GenerateTrackingNumber()
    {
        return $"ST-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}

