@page "/track"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>
<p class="text-muted">Enter your tracking number to view shipment status and estimated delivery.</p>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control form-control-lg" placeholder="e.g. ST-20260501-10001"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary btn-lg" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning">
        <strong>Not Found:</strong> @errorMessage
    </div>
}

@if (shipment is not null)
{
    <div class="card shadow-sm">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h4 class="mb-0">
                <code>@shipment.TrackingNumber</code>
            </h4>
            <span class="badge fs-6 @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row g-4">
                <div class="col-md-6">
                    <h5>Shipment Details</h5>
                    <dl class="row mb-0">
                        <dt class="col-sm-5">From</dt>
                        <dd class="col-sm-7">@shipment.Origin</dd>

                        <dt class="col-sm-5">To</dt>
                        <dd class="col-sm-7">@shipment.Destination</dd>

                        <dt class="col-sm-5">Sender</dt>
                        <dd class="col-sm-7">@shipment.SenderName</dd>

                        <dt class="col-sm-5">Recipient</dt>
                        <dd class="col-sm-7">@shipment.RecipientName</dd>

                        <dt class="col-sm-5">Weight</dt>
                        <dd class="col-sm-7">@shipment.WeightKg.ToString("F1") kg</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <h5>Delivery Timeline</h5>
                    <dl class="row mb-0">
                        <dt class="col-sm-5">Shipped</dt>
                        <dd class="col-sm-7">@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                        <dt class="col-sm-5">Est. Delivery</dt>
                        <dd class="col-sm-7">
                            <strong>@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</strong>
                            @if (shipment.Status != ShipmentStatus.Delivered && shipment.EstimatedDelivery > DateTime.UtcNow)
                            {
                                <br />
                                <small class="text-muted">
                                    @((shipment.EstimatedDelivery - DateTime.UtcNow).Days) days remaining
                                </small>
                            }
                        </dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt class="col-sm-5">Delivered On</dt>
                            <dd class="col-sm-7 text-success fw-bold">
                                @shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy 'at' h:mm tt")
                            </dd>
                        }
                    </dl>
                </div>
            </div>

            @if (!string.IsNullOrWhiteSpace(shipment.Notes))
            {
                <hr />
                <div>
                    <h6>Notes</h6>
                    <p class="mb-0 text-muted">@shipment.Notes</p>
                </div>
            }

            <!-- Status progress bar -->
            <hr />
            <h6>Shipment Progress</h6>
            <div class="d-flex justify-content-between position-relative mt-3 mb-2">
                @{
                    var steps = new[] {
                        ShipmentStatus.Pending,
                        ShipmentStatus.PickedUp,
                        ShipmentStatus.InTransit,
                        ShipmentStatus.OutForDelivery,
                        ShipmentStatus.Delivered
                    };
                    var currentIdx = Array.IndexOf(steps, shipment.Status);
                    var isException = shipment.Status == ShipmentStatus.Delayed || shipment.Status == ShipmentStatus.Returned;
                }
                @for (int i = 0; i < steps.Length; i++)
                {
                    var step = steps[i];
                    var isActive = !isException && i <= currentIdx;
                    <div class="text-center flex-fill">
                        <div class="rounded-circle d-inline-flex align-items-center justify-content-center @(isActive ? "bg-success text-white" : "bg-light border")"
                             style="width: 36px; height: 36px;">
                            @if (isActive)
                            {
                                <span>✓</span>
                            }
                            else
                            {
                                <span class="text-muted">@(i + 1)</span>
                            }
                        </div>
                        <div class="small mt-1">@step</div>
                    </div>
                }
            </div>
            @if (isException)
            {
                <div class="alert @(shipment.Status == ShipmentStatus.Delayed ? "alert-warning" : "alert-danger") mt-2 mb-0">
                    <strong>@shipment.Status:</strong>
                    @(shipment.Status == ShipmentStatus.Delayed
                        ? "This shipment is experiencing delays. We apologize for the inconvenience."
                        : "This shipment has been returned to the sender.")
                </div>
            }
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                errorMessage = "No shipment found with that tracking number. Please verify and try again.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"An error occurred: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}

