@code {
    private List<ShipmentDto>? shipments;
    private string searchTerm = "";
    private string statusFilter = "";
    private string? errorMessage;
    private bool showCreateForm;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
    private int? editingId;
    private ShipmentStatus editStatus;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            var url = "/api/shipments?";
            if (!string.IsNullOrEmpty(statusFilter)) url += $"status={statusFilter}&";
            if (!string.IsNullOrEmpty(searchTerm)) url += $"search={Uri.EscapeDataString(searchTerm)}&";
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>(url.TrimEnd('&', '?'));
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task HandleSearch()
    {
        await LoadShipments();
    }

    private async Task CreateShipment()
    {
        try
        {
            var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
            if (response.IsSuccessStatusCode)
            {
                newShipment = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
                showCreateForm = false;
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to create shipment.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private void StartEdit(ShipmentDto shipment)
    {
        editingId = shipment.Id;
        editStatus = shipment.Status;
    }

    private async Task SaveStatus(int id)
    {
        try
        {
            var response = await Http.PutAsJsonAsync($"/api/shipments/{id}/status",
                new { Status = editStatus, Notes = (string?)null });
            if (response.IsSuccessStatusCode)
            {
                editingId = null;
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to update status.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}
