                                    </select>
                                    <button class="btn btn-sm btn-success" @onclick="() => SaveStatus(shipment.Id)">Save</button>
                                    <button class="btn btn-sm btn-secondary" @onclick="() => editingId = null">✕</button>
                                </div>
                            }
                            else
                            {
                                <button class="btn btn-sm btn-outline-primary"
                                        @onclick="() => StartEdit(shipment)">
                                    Update
                                </button>
                            }
                        </td>
                    </tr>
